mapper.select:
select u.id, u.username, s.id as staffId, u.role_id as roleId, u.status, s.name as staffName, u.update_time, u.create_time, u.last_login_time as lastLoginTime from sys_user u left join staff_member s on s.id = u.staff_id
and u.username like concat('%',#{username},'%')
and u.status = #{status}
and u.role_id = #{roleId}
order by u.create_time desc, u.id desc
